prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
prefix dcat: <http://www.w3.org/ns/dcat#>
prefix void: <http://rdfs.org/ns/void#>
prefix dct: <http://purl.org/dc/terms/title>
prefix prov: <https://www.w3.org/ns/prov#>
prefix foaf: <http://xmlns.com/foaf/0.1/>
prefix : <http://bio2rdf.org/>

: a dcat:Dataset, void:Dataset;
  dct:title "Bio2RDF";
  dct:alternative "Bio2RDF";
  dct:description "Bio2RDF is a large-scale bioinformatics knowledge base and Linked Open Data (LOD) project that transforms heterogeneous life science databases into interconnected Resource Description Framework (RDF) resources"@en;
  <http://qudt.org/schema/qudt/> "Bio2RDF";
 <http://xmlns.com/foaf/0.1/page> "http://bio2rdf.org";
   <http://www.w3.org/2000/01/rdf-schema#seeAlso> <https://www.bio2rdf.org/about> ;
   prov:qualifiedAttribution [
       prov:agent [
          a prov:Agent;
          foaf:name "Michel Dumontier";
          foaf:mbox "michel.dumontier@bio2rdf.org";
       ] 
   ] 

.
